d353672e-c5c8-4b52-9946-cf371233aeff	ca86f924-9b0c-4b32-8ab3-6e18faf54a41	\N	CSS Grid: ╤В╨╛╤А ╨╢╥п╨╣╨╡╤Б╤Ц	# CSS Grid тАФ ╨Х╨║╤Ц ╙й╨╗╤И╨╡╨╝╨┤╤Ц ╤В╨╛╤А\n\nFlexbox тАФ ╨▒╤Ц╤А ╙й╨╗╤И╨╡╨╝ (╨╢╨╛╨╗ ╨╜╨╡╨╝╨╡╤Б╨╡ ╨▒╨░╥У╨░╨╜).\nGrid тАФ ╨╡╨║╤Ц ╙й╨╗╤И╨╡╨╝ ╨▒╤Ц╤А ╨╝╨╡╨╖╨│╤Ц╨╗╨┤╨╡ (╨╢╨╛╨╗ + ╨▒╨░╥У╨░╨╜).\n\n## ╨Ж╤Б╨║╨╡ ╥Ы╨╛╤Б╤Г\n\n```css\n.grid-container {\n  display: grid;\n\n  /* 3 ╨▒╨░╥У╨░╨╜: ╙Щ╤А╥Ы╨░╨╣╤Б╤Л╤Б╤Л ╤В╨╡╥г ╨║╨╡╥г╨┤╤Ц╨║╤В╨╡ */\n  grid-template-columns: 1fr 1fr 1fr;\n  grid-template-columns: repeat(3, 1fr); /* ╨╢╨╛╥У╨░╤А╤Л╨╝╨╡╨╜ ╨▒╤Ц╤А╨┤╨╡╨╣ */\n\n  /* ╨Р╤А╨╜╨░╨╣╤Л ╙й╨╗╤И╨╡╨╝╨┤╨╡╤А */\n  grid-template-columns: 200px 1fr 200px;\n\n  /* 2 ╨╢╨╛╨╗: 100px + ╥Ы╨░╨╗╥У╨░╨╜ ╨╛╤А╤Л╨╜ */\n  grid-template-rows: 100px 1fr;\n\n  /* ╨н╨╗╨╡╨╝╨╡╨╜╤В╤В╨╡╤А ╨░╤А╨░╤Б╤Л */\n  gap: 24px;\n  column-gap: 16px;\n  row-gap: 8px;\n}\n```\n\n## fr ╨▒╤Ц╤А╨╗╤Ц╨│╤Ц\n\n`fr` тАФ Grid-╤В╨╡╨│╤Ц ╨▒╥▒╤А╤Л╤И ╨▒╤Ц╤А╨╗╤Ц╨│╤Ц (fraction = ╥п╨╗╨╡╤Б).\n\n```css\ngrid-template-columns: 1fr 2fr 1fr;\n/* 25% | 50% | 25% */\n```\n\n## ╨н╨╗╨╡╨╝╨╡╨╜╤В╤В╤Ц╥г ╨╛╤А╨╜╤Л╨╜ ╨▒╨╡╨╗╨│╤Ц╨╗╨╡╤Г\n\n```css\n.header {\n  grid-column: 1 / -1;  /* ╨▒╨░╤А╨╗╤Л╥Ы ╨▒╨░╥У╨░╨╜╨┤╨░╤А╥У╨░ ╤Б╨╛╨╖╤Л╨╗╤Г */\n}\n\n.sidebar {\n  grid-column: 1;        /* 1-╤И╤Ц ╨▒╨░╥У╨░╨╜ */\n  grid-row: 1 / 3;       /* 1-╨┤╨╡╨╜ 3-╨║╨╡ ╨┤╨╡╨╣╤Ц╨╜ (2 ╨╢╨╛╨╗) */\n}\n\n.main {\n  grid-column: 2 / -1;  /* 2-╤И╤Ц ╨▒╨░╥У╨░╨╜╨╜╨░╨╜ ╤Б╨╛╥г╤Л╨╜╨░ */\n}\n```\n\n## ╨Р╤В╨░╨╗╥У╨░╨╜ ╨░╨╣╨╝╨░╥Ы╤В╨░╤А\n\n```css\n.layout {\n  display: grid;\n  grid-template-areas:\n    "header header"\n    "sidebar main"\n    "footer footer";\n  grid-template-columns: 250px 1fr;\n  grid-template-rows: 60px 1fr 60px;\n}\n\n.header  { grid-area: header; }\n.sidebar { grid-area: sidebar; }\n.main    { grid-area: main; }\n.footer  { grid-area: footer; }\n```\n\n## Responsive Grid\n\n```css\n.cards {\n  display: grid;\n  /* auto-fill: ╤Б╤Л╤П╨┤╤Л ╨╝╨░ тАФ ╤В╨╛╨╗╤В╤Л╤А╨░, min 280px */\n  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));\n  gap: 24px;\n}\n```\n\n╨С╥▒╨╗ тАФ ╤Н╨║╤А╨░╨╜ ╙й╨╗╤И╨╡╨╝╤Ц╨╜╨╡ ╥Ы╨░╤А╨░╨╣ ╨▒╨░╥У╨░╨╜ ╤Б╨░╨╜╤Л╨╜ ╨░╨▓╤В╨╛╨╝╨░╤В╤В╤Л ╤А╨╡╤В╤В╨╡╨╣╨┤╤Ц!	\N	╨в╨░╨┐╤Б╤Л╤А╨╝╨░: CSS Grid-╤В╨╡ 3 ╨▒╤Ц╤А╨┤╨╡╨╣ ╨▒╨░╥У╨░╨╜╨┤╤Л ╤В╨╛╤А ╨╢╨░╤Б╨░╨╣╤В╤Л╨╜ ╨╜╥▒╤Б╥Ы╨░?\n\n.grid {\n  display: grid;\n  grid-template-columns: repeat(___, 1fr);\n}\n\n╨в╨╡╨║ ╤Б╨░╨╜╨┤╤Л ╨╢╨░╨╖╤Л╥г╤Л╨╖ (╨╢╨░╤Г╨░╨┐: 3)	3	7	2026-03-03 20:34:17.924
